mapper.select:
select *
from batch.file_record
where tenant_id = #{tenantId}
  and id = #{fileId}

select count(1)
from batch.pipeline_instance
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and run_status in (#{createdStatus}, #{runningStatus}, #{compensatingStatus})

select count(1)
from batch.file_dispatch_record
where tenant_id = #{tenantId}
  and file_id = #{fileId}
  and (dispatch_status in (#{dispatchCreatedStatus}, #{dispatchSentStatus}) or receipt_status = #{receiptPendingStatus})

select *
from batch.file_dispatch_record
where tenant_id = #{tenantId}
  and file_id = #{fileId}

    and channel_code = #{channelCode}

order by id desc
limit 1

select related_job_instance_id
from batch.pipeline_instance
where id = #{pipelineInstanceId}

select *
from batch.file_record
where file_status = #{archivedStatus}
  and updated_at < #{cutoff}
order by updated_at asc
limit #{limit}

select tenant_id, metadata_json ->> 'fileGroupCode' as file_group_code, coalesce(metadata_json ->> 'waitFileGroupMode', 'ALL_OF') as wait_file_group_mode, coalesce(metadata_json ->> 'requiredFileSet', '') as required_file_set, coalesce(metadata_json ->> 'arrivalTimeoutAction', 'MANUAL_CONFIRM') as arrival_timeout_action, coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') as arrival_state, max(metadata_json ->> 'expectedArrivalTime') as expected_arrival_time, max(metadata_json ->> 'latestTolerableTime') as latest_tolerable_time, count(1) as arrived_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = 'TRIGGERED') as triggered_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = 'TIMEOUT') as timeout_count, count(1) filter (where coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') like 'WAITING%') as waiting_count, max(updated_at) as last_updated_at from batch.file_record where jsonb_exists(metadata_json, 'fileGroupCode')
and tenant_id = #{tenantId}
and metadata_json ->> 'fileGroupCode' = #{fileGroupCode}
and coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') = #{arrivalState}
group by tenant_id, metadata_json ->> 'fileGroupCode', coalesce(metadata_json ->> 'waitFileGroupMode', 'ALL_OF'), coalesce(metadata_json ->> 'requiredFileSet', ''), coalesce(metadata_json ->> 'arrivalTimeoutAction', 'MANUAL_CONFIRM'), coalesce(metadata_json ->> 'arrivalState', 'WAITING_ARRIVAL') order by last_updated_at desc, file_group_code asc

select coalesce(max(extract(epoch from (current_timestamp - started_at))), 0)::bigint
from batch.pipeline_instance
where tenant_id = #{tenantId}
  and run_status = #{runningStatus}
  and started_at is not null
  and started_at > current_timestamp - (#{maxAgeSeconds} * interval '1 second')

select count(1)
from batch.file_record
where tenant_id = #{tenantId}
  and storage_path = #{storagePath}

mapper.update:
update batch.file_record
set file_status = #{nextStatus},
    metadata_json = coalesce(metadata_json, '{}'::jsonb) || coalesce(#{metadataJson,jdbcType=VARCHAR}::jsonb, '{}'::jsonb),
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{fileId}
  and file_status = #{currentStatus}

update batch.file_record
set metadata_json = coalesce(metadata_json, '{}'::jsonb) || coalesce(#{metadataJson,jdbcType=VARCHAR}::jsonb, '{}'::jsonb),
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{fileId}

update batch.file_record
set file_size_bytes = #{fileSizeBytes},
    metadata_json = coalesce(metadata_json, '{}'::jsonb) || coalesce(#{metadataJson,jdbcType=VARCHAR}::jsonb, '{}'::jsonb),
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{fileId}
